class Solution {
public:
    int coinChange(vector<int>& coins, int amount) {
        int Max = amount + 1;
        vector<int> dp(amount + 1, Max); // 初值 amount+1 表示暂不可达
        dp[0] = 0;
        for (int i = 1; i <= amount; ++i) {
            for (int j = 0; j < (int)coins.size(); ++j) {
                if (coins[j] <= i) {
                    dp[i] = min(dp[i], dp[i - coins[j]] + 1); // 枚举最后一枚硬币，取最少数量
                }
            }
        }
        return dp[amount] > amount ? -1 : dp[amount];
    }
};
